SELECT *
FROM check_record_weight_configs
WHERE deleted = 0
AND record_id = #{recordId}
AND config_level = #{configLevel}
ORDER BY created_at ASC

SELECT * FROM check_record_weight_configs WHERE deleted = 0 AND record_id = #{recordId} AND config_level = 'ITEM'
AND category_id = #{categoryId}
ORDER BY category_id ASC, item_id ASC
